import os
import re
import sys
import mysql.connector

def main():
    host = input("MySQL host: ").strip() or "localhost"
    port = int((input("MySQL port: ").strip() or "3306"))
    user = input("MySQL user: ").strip()
    password = input("MySQL password: ").strip()
    database = input("MySQL database: ").strip()
    table = input("Target table: ").strip()
    file_path = input("Path to import file: ").strip()

    if not user or not database or not table or not file_path:
        print("Missing required input.")
        sys.exit(1)

    abs_path = os.path.abspath(file_path)
    if not os.path.isfile(abs_path):
        print("File does not exist:", abs_path)
        sys.exit(1)

    if not re.fullmatch(r"[A-Za-z0-9_]+", table):
        print("Invalid table name.")
        sys.exit(1)

    try:
        conn = mysql.connector.connect(
            host=host,
            port=port,
            user=user,
            password=password,
            database=database,
            allow_local_infile=True
        )
        cursor = conn.cursor()
        cursor.execute("SET GLOBAL local_infile = 1")
        cursor.execute("SET SESSION local_infile = 1")

        escaped_path = abs_path.replace("\\", "\\\\").replace("'", "\\'")
        sql = (
            "LOAD DATA LOCAL INFILE %s "
            f"INTO TABLE `{table}` "
            "FIELDS TERMINATED BY ',' "
            'OPTIONALLY ENCLOSED BY \'"\' '
            "LINES TERMINATED BY '\\n' "
            "IGNORE 1 LINES"
        )

        cursor.execute(sql, (escaped_path,))
        conn.commit()
        print(f"Imported file into {table}: {abs_path}")

    except mysql.connector.Error as e:
        print("MySQL error:", e)
        sys.exit(1)
    finally:
        try:
            cursor.close()
        except Exception:
            pass
        try:
            conn.close()
        except Exception:
            pass

if __name__ == "__main__":
    main()